function mergeKLists(lists: (ListNode | null)[]): ListNode | null {
  if (lists.length === 0) return null;

  // Min heap using PriorityQueue pattern
  class MinHeap {
    private heap: [number, ListNode][] = [];

    push(val: number, node: ListNode): void {
      this.heap.push([val, node]);
      this.bubbleUp(this.heap.length - 1);
    }

    pop(): [number, ListNode] | undefined {
      if (this.heap.length === 0) return undefined;
      const result = this.heap[0];
      const last = this.heap.pop()!;
      if (this.heap.length > 0) {
        this.heap[0] = last;
        this.bubbleDown(0);
      }
      return result;
    }

    private bubbleUp(index: number): void {
      while (index > 0) {
        const parentIndex = Math.floor((index - 1) / 2);
        if (this.heap[index][0] < this.heap[parentIndex][0]) {
          [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
          index = parentIndex;
        } else {
          break;
        }
      }
    }

    private bubbleDown(index: number): void {
      while (true) {
        let smallest = index;
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;

        if (leftChild < this.heap.length && this.heap[leftChild][0] < this.heap[smallest][0]) {
          smallest = leftChild;
        }
        if (rightChild < this.heap.length && this.heap[rightChild][0] < this.heap[smallest][0]) {
          smallest = rightChild;
        }
        if (smallest !== index) {
          [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
          index = smallest;
        } else {
          break;
        }
      }
    }
  }

  const heap = new MinHeap();
  const dummy = new ListNode(0);
  let current = dummy;

  // Add first node of each list to heap
  for (const list of lists) {
    if (list !== null) {
      heap.push(list.val, list);
